// Buka DevTools Console dan coba:

// === Core ===
d.info('Halo dari DonatJS!');
d.color(5); // array 5 warna interpolasi
d.model.nama; // nama modul aktif

// === SVG ===
Object.keys(getIcons()).length;  // jumlah ikon di cache
svgIcon('donat', '64', 'var(--pColor)'); // render ke string
addIcon('test-circle', 'M12 2 A10 10 0 1 0 12 22 A10 10 0 1 0 12 2');

// === Skin ===
Theme.list(); // semua pilihan tersedia
Theme.set('wafel', 'merah', 'framework');
refreshIcons();
Theme.set('donat', 'hijau', 'framework'); // kembalikan
refreshIcons();

// Palet custom runtime:
Theme.addPallet('tosca', {
  pColor:'#2ec4b6', pLightColor:'#cbf3f0', pDarkColor:'#1a936f'
});
Theme.setPallet('tosca');
refreshIcons();

// === UI ===
navigate('web/page/portal-docs');  // navigasi
ui.fetch.clear();                  // kosongkan HTTP cache
console.log(ui.render);            // inspect render engine

// === POS ===
pos.addItem('x', 'Produk Test', 'Rp 10.000');
pos.addItem('x', 'Produk Test', 'Rp 10.000'); // qty++
pos.cart; // inspect state
pos.getTotal(); // 10000
pos.openCart(); // tampilkan sidePanel
pos.clearCart();

// === Login ===
login.controller.isLogged(); // boolean
JSON.parse(d.getls('data') || 'null'); // data user
